import{_ as n,o as h,c as i,a0 as l}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Dữ liệu","description":"","frontmatter":{"title":"Dữ liệu"},"headers":[],"relativePath":"data.md","filePath":"data.md"}'),o={name:"data.md"};function c(a,t,u,g,r,e){return h(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="du-lieu" tabindex="-1">Dữ liệu <a class="header-anchor" href="#du-lieu" aria-label="Permalink to &quot;Dữ liệu&quot;">​</a></h1><p>Mô-đun <strong>Dữ liệu (Data)</strong> trong ABNERP cung cấp các công cụ mạnh mẽ để quản lý, nhập, xuất và thao tác dữ liệu hàng loạt. Các công cụ này giúp doanh nghiệp tiết kiệm thời gian và giảm thiểu sai sót khi làm việc với khối lượng dữ liệu lớn.</p><h2 id="cong-cu-nhap-du-lieu" tabindex="-1">Công cụ nhập dữ liệu <a class="header-anchor" href="#cong-cu-nhap-du-lieu" aria-label="Permalink to &quot;Công cụ nhập dữ liệu&quot;">​</a></h2><p><strong>Công cụ nhập dữ liệu (Data Import Tool)</strong> cho phép nhập dữ liệu từ tệp Excel (.xlsx) hoặc CSV vào hệ thống. Công cụ này hỗ trợ:</p><ul><li><strong>Nhập tất cả loại dữ liệu</strong>: khách hàng, nhà cung cấp, mặt hàng, đơn hàng, hóa đơn, v.v.</li><li><strong>Mẫu nhập (Template)</strong>: tự động tạo mẫu Excel với đầy đủ cột và hướng dẫn</li><li><strong>Ánh xạ trường</strong>: tự động phát hiện và ánh xạ cột trong tệp với trường trong hệ thống</li><li><strong>Xác thực dữ liệu</strong>: kiểm tra lỗi trước khi nhập, báo cáo chi tiết các dòng lỗi</li><li><strong>Nhập có điều kiện</strong>: chỉ nhập dữ liệu hợp lệ, bỏ qua hoặc đánh dấu dữ liệu lỗi</li></ul><p>Sau khi nhập, người dùng có thể xem nhật ký nhập (Import Log) để kiểm tra chi tiết những bản ghi nào đã được tạo và những bản ghi nào bị lỗi kèm nguyên nhân.</p><h2 id="đoi-ten-hang-loat" tabindex="-1">Đổi tên hàng loạt <a class="header-anchor" href="#đoi-ten-hang-loat" aria-label="Permalink to &quot;Đổi tên hàng loạt&quot;">​</a></h2><p><strong>Đổi tên hàng loạt (Bulk Rename)</strong> cho phép đổi tên nhiều bản ghi cùng lúc theo quy tắc định trước. Tính năng này đặc biệt hữu ích khi cần:</p><ul><li>Thay đổi mã sản phẩm hàng loạt (mã cũ → mã mới, thêm tiền tố/hậu tố)</li><li>Đồng bộ hóa tên bản ghi theo chuẩn đặt tên mới của công ty</li><li>Cập nhật tên khách hàng hoặc nhà cung cấp khi có thay đổi thông tin</li></ul><p>Người dùng có thể tải lên tệp Excel với cấu trúc &quot;Tên cũ → Tên mới&quot; hoặc sử dụng các quy tắc thay thế (thay thế chuỗi, thêm tiền tố, thêm hậu tố).</p><h2 id="xuat-du-lieu" tabindex="-1">Xuất dữ liệu <a class="header-anchor" href="#xuat-du-lieu" aria-label="Permalink to &quot;Xuất dữ liệu&quot;">​</a></h2><p><strong>Xuất dữ liệu (Data Export)</strong> cho phép xuất dữ liệu từ hệ thống ra tệp Excel hoặc CSV với các tùy chọn linh hoạt:</p><ul><li><strong>Chọn loại dữ liệu</strong>: xuất toàn bộ hoặc một phần dữ liệu của loại bản ghi bất kỳ</li><li><strong>Chọn trường</strong>: chỉ chọn những trường cần thiết, loại bỏ trường không quan trọng</li><li><strong>Bộ lọc</strong>: lọc dữ liệu trước khi xuất (theo ngày tháng, trạng thái, khách hàng, v.v.)</li><li><strong>Định dạng ngày và số</strong>: xuất theo định dạng mong muốn</li></ul><p>Công cụ xuất dữ liệu đặc biệt hữu ích cho việc sao lưu, báo cáo ngoại vi và phân tích dữ liệu chuyên sâu.</p><h3 id="luu-y-bao-mat" tabindex="-1">Lưu ý bảo mật <a class="header-anchor" href="#luu-y-bao-mat" aria-label="Permalink to &quot;Lưu ý bảo mật&quot;">​</a></h3><ul><li>Công cụ nhập và xuất dữ liệu tuân thủ nghiêm ngặt hệ thống phân quyền của ABNERP</li><li>Người dùng chỉ có thể nhập/xuất dữ liệu thuộc quyền được cấp</li><li>Nhật ký nhập/xuất dữ liệu được lưu lại để phục vụ kiểm toán</li></ul>',16)])])}const s=n(o,[["render",c]]);export{d as __pageData,s as default};
